+@code {
+    [Parameter, EditorRequired]
+    public List<string> Categories { get; set; } = [];
+
+    [Parameter]
+    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }
+
+    [Parameter]
+    public EventCallback OnFiltersCleared { get; set; }
+
+    private HashSet<string> _selectedCategories = [];
+    private decimal? _minPrice;
+    private decimal? _maxPrice;
+    private bool _inStockOnly;
+
+    private void ToggleCategory(string category, bool isChecked)
+    {
+        if (isChecked)
+            _selectedCategories.Add(category);
+        else
+            _selectedCategories.Remove(category);
+    }
+
+    private async Task ApplyFilters()
+    {
+        var filter = new ProductFilter(
+            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
+            MinPrice: _minPrice,
+            MaxPrice: _maxPrice,
+            InStockOnly: _inStockOnly
+        );
+        await OnFiltersApplied.InvokeAsync(filter);
+    }
+
+    private async Task ClearFilters()
+    {
+        _selectedCategories.Clear();
+        _minPrice = null;
+        _maxPrice = null;
+        _inStockOnly = false;
+        await OnFiltersCleared.InvokeAsync();
+    }
+
+    private static decimal? ParseDecimal(object? value)
+    {
+        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
+            return null;
+        return decimal.TryParse(value.ToString(), out var result) ? result : null;
+    }
+}
